mapper.insert:
		/*
		 SQL ID : AcadSchDAO.insert
			 설  명 : 일정 관리 등록
 	   	*/
 	   	INSERT INTO TB_HOME_ACAD_SCH (
 	   		  ACAD_SCH_SN
			, ORG_ID
			, UNIV_CD
			, SYSJOB_SCHDL_TYCD
			, CALENDAR_REF_CD
			, SYSJOB_SCHDL_SYMD
			, SYSJOB_SCHDL_EYMD
			, ACAD_SCH_NM
			, SCH_CNTS
			, SCH_CNTS_TYPE
			, USEYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
 	   	) VALUES (
 	   		  #{acadSchSn}
 	   		, #{orgId}
 	   		, #{uniCd}
 	   		, #{calendarCtgr}
 	   		, #{calendarRefCd}
 	   		, #{schStartDt}
 	   		, #{schEndDt}
 	   		, #{acadSchNm}
 	   		, #{schCnts}
 	   		, #{schCntsType}
 	   		, NVL(#{useYn}, 'Y')
 	   		, #{rgtrId}
 	   		, FN_DTTM()
 	   		, #{mdfrId}
 	   		, FN_DTTM()
 	   	)

mapper.update:
		/*
		 SQL ID : AcadSchDAO.update
			 설  명 : 일정 관리 수정
 	   	*/
 	   	UPDATE TB_HOME_ACAD_SCH SET
 	   		  MDFR_ID = #{mdfrId}
			, MOD_DTTM = FN_DTTM()

			, ORG_ID = #{orgId}


			, UNIV_CD = #{uniCd}


			, SYSJOB_SCHDL_TYCD = #{calendarCtgr}


			, CALENDAR_REF_CD = #{calendarRefCd}


			, SYSJOB_SCHDL_SYMD = #{schStartDt}


			, SYSJOB_SCHDL_EYMD = #{schEndDt}


			, ACAD_SCH_NM = #{acadSchNm}


			, SCH_CNTS = #{schCnts}


			, SCH_CNTS_TYPE = #{schCntsType}

		 WHERE ACAD_SCH_SN = #{acadSchSn}

mapper.delete:
		/*
		 SQL ID : AcadSchDAO.delete
			 설  명 : 일정 관리 삭제
 	   	*/
 	   	DELETE FROM TB_HOME_ACAD_SCH
 	   	 WHERE ACAD_SCH_SN = #{acadSchSn}
